from flask import Blueprint, request, jsonify, current_app
from functools import wraps
from datetime import datetime

api = Blueprint('api', __name__)

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        from flask import g
        current_user = getattr(g, 'current_user', None)
        if not current_user:
            return jsonify({'error': 'Authentication required'}), 401
        if current_user.get('role') != 'admin':
            return jsonify({'error': 'Admin privileges required'}), 403
        return f(*args, **kwargs)
    return decorated_function

def get_user_from_db(user_id):
    from flask import g
    db = getattr(g, 'db', None)
    if db:
        return db.get('users', {}).get(str(user_id))
    return None

def update_user_in_db(user_id, user_data):
    from flask import g
    db = getattr(g, 'db', None)
    if db:
        if 'users' not in db:
            db['users'] = {}
        db['users'][str(user_id)] = user_data
        return True
    return False

@api.route('/api/users/<int:user_id>', methods=['PUT'])
@admin_required
def update_user(user_id):
    from flask import g
    current_user = g.current_user
    
    target_user = get_user_from_db(user_id)
    if not target_user:
        return jsonify({'error': 'User not found'}), 404
    
    if not isinstance(target_user, dict):
        return jsonify({'error': 'Invalid user data'}), 500
    
    request_data = request.get_json()
    if not request_data:
        return jsonify({'error': 'No data provided'}), 400
    
    ALLOWED_FIELDS = {
        'email': str,
        'username': str,
        'role': str,
        'account_status': str,
        'subscription_tier': str
    }
    
    VALID_ROLES = {'user', 'moderator', 'admin'}
    VALID_STATUSES = {'active', 'suspended'}
    VALID_TIERS = {'free', 'pro', 'enterprise'}
    
    if current_user.get('id') == user_id and 'role' in request_data:
        if request_data['role'] != current_user.get('role'):
            return jsonify({'error': 'Cannot modify your own role'}), 403
    
    if current_user.get('id') == user_id and 'account_status' in request_data:
        if request_data['account_status'] == 'suspended':
            return jsonify({'error': 'Cannot suspend your own account'}), 403
    
    updates = {}
    for field, value in request_data.items():
        if field not in ALLOWED_FIELDS:
            continue
        
        expected_type = ALLOWED_FIELDS[field]
        if not isinstance(value, expected_type):
            return jsonify({'error': f'Invalid type for field {field}'}), 400
        
        if field == 'email':
            if not value or '@' not in value or len(value) > 255:
                return jsonify({'error': 'Invalid email format'}), 400
            updates['email'] = value.strip().lower()
        
        elif field == 'username':
            if not value or len(value) < 3 or len(value) > 50:
                return jsonify({'error': 'Username must be between 3 and 50 characters'}), 400
            if not value.replace('_', '').replace('-', '').isalnum():
                return jsonify({'error': 'Username can only contain alphanumeric characters, underscores, and hyphens'}), 400
            updates['username'] = value.strip()
        
        elif field == 'role':
            if value not in VALID_ROLES:
                return jsonify({'error': f'Invalid role. Must be one of: {", ".join(VALID_ROLES)}'}), 400
            updates['role'] = value
        
        elif field == 'account_status':
            if value not in VALID_STATUSES:
                return jsonify({'error': f'Invalid account status. Must be one of: {", ".join(VALID_STATUSES)}'}), 400
            updates['account_status'] = value
        
        elif field == 'subscription_tier':
            if value not in VALID_TIERS:
                return jsonify({'error': f'Invalid subscription tier. Must be one of: {", ".join(VALID_TIERS)}'}), 400
            updates['subscription_tier'] = value
    
    if not updates:
        return jsonify({'error': 'No valid fields to update'}), 400
    
    updated_user = target_user.copy()
    updated_user.update(updates)
    updated_user['updated_at'] = datetime.utcnow().isoformat()
    updated_user['updated_by'] = current_user.get('id')
    
    if not update_user_in_db(user_id, updated_user):
        return jsonify({'error': 'Failed to update user'}), 500
    
    response_user = {
        'id': updated_user.get('id'),
        'email': updated_user.get('email'),
        'username': updated_user.get('username'),
        'role': updated_user.get('role'),
        'account_status': updated_user.get('account_status'),
        'subscription_tier': updated_user.get('subscription_tier'),
        'updated_at': updated_user.get('updated_at')
    }
    
    return jsonify({
        'message': 'User updated successfully',
        'user': response_user
    }), 200